#include <bits/stdc++.h> 
using namespace std;
#define ll long long
const int N=105,M=25;
struct node
{
	ll v,val;
	bool operator<(const node other) const
	{
		return val>other.val; 
	}
};

vector<node> g[M];
int n,m,k,e,dis[M],vis[M],d,vis2[M][N],shan[M],ans[N][N];
ll dp[N];
void dij()
{
	memset(vis,0,sizeof(vis));
	memset(dis,0x3f,sizeof(dis));
	priority_queue<node> pq;
	dis[1]=0;
	pq.push(node{1,0});
	while(!pq.empty())
	{
		node t=pq.top();
		pq.pop();
		int u=t.v;
		if(vis[u]) continue;
		vis[u]=1;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].val;
			if(shan[v]) continue;
			if(!vis[v]&&dis[u]+w<dis[v])
			{
				dis[v]=dis[u]+w;
				pq.push(node{v,dis[v]});
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m>>k>>e;
	for(int i=0;i<=n;i++) dp[i]=0x3f3f3f3f;
	for(int i=1;i<=e;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	cin>>d;
	for(int i=1;i<=d;i++)
	{
		int num,x,y;
		cin>>num>>x>>y;
		for(int j=x;j<=y;j++)
		{
			vis2[num][j]=1;
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			memset(shan,0,sizeof(shan));
			for(int ii=1;ii<=m;ii++)
			{
				for(int jj=i;jj<=j;jj++)
				{
					if(vis2[ii][jj]) shan[ii]=1;
				}
			}
			dij();
//			for(int i=1;i<=n;i++) cout<<shan[i]<<"  ";
//			cout<<" : "<<dis[m]<<"\n";
			ans[i][j]=dis[m];
		}
	}
	for(int i=1;i<=n;i++)
	{
		dp[i]=(ll)ans[1][i]*i;
//		cout<<i<<"  : ";
		for(int j=0;j<=i-1;j++)
		{
//			cout<<"bb "<<j<<" : "<<dp[j]<<" + "<<ans[j+1][i]<<"*"<<(i-j)<<" + "<<k<<"\n";
			if(ans[j+1][i]==0x3f3f3f3f) continue;
			dp[i]=min(dp[i],dp[j]+(ll)ans[j+1][i]*(i-j)+k);
		}
//		cout<<dp[i]<<" aaa\n";
	}
	cout<<dp[n];
	return 0;
}
